// Minimal CUDA TOP Plugin skeleton
// Inherits from TOP_CPlusPlusBase (Derivative C++ TOP SDK)
#include "TOP_CPlusPlusBase.h"
#include <cuda_runtime.h>

using namespace TD;

// CUDA kernel: invert image
__global__ void invertKernel(float4* dst, const float4* src, int width, int height) {
    int x = blockIdx.x * blockDim.x + threadIdx.x;
    int y = blockIdx.y * blockDim.y + threadIdx.y;
    if (x >= width || y >= height) return;
    int idx = y * width + x;
    dst[idx] = make_float4(1.0f - src[idx].x,
                           1.0f - src[idx].y,
                           1.0f - src[idx].z,
                           src[idx].w);
}

class MyCUDATOP : public TOP_CPlusPlusBase {
public:
    void execute(TOP_Output* output, const OP_Inputs* inputs, void* reserved) override {
        const OP_TOPInput* topIn = inputs->getInputTOP(0);
        if (!topIn) return;

        int w = topIn->textureDesc.width;
        int h = topIn->textureDesc.height;

        // Map TD textures to CUDA via the SDK's CUDA acquire/release API,
        // then launch the kernel on the device pointers.
        dim3 block(16, 16);
        dim3 grid((w + block.x - 1) / block.x, (h + block.y - 1) / block.y);
        invertKernel<<<grid, block>>>(
            (float4*)d_dst, (float4*)d_src, w, h);
        cudaDeviceSynchronize();
        // Copy result back into the output texture supplied by TOP_Output.
    }
};

// Particle simulation via ping-pong (GLSL TOP pixel shader)
// Input 0 (sTD2DInputs[0]): Feedback TOP, current particle state
//                          (pos = RG, vel = BA, each stored as 0..1)
// Input 1 (sTD2DInputs[1], OPTIONAL): force-field texture
// Do NOT add a #version line: TouchDesigner injects it.

uniform float uDt;       // timestep
uniform vec2  uGravity;  // e.g. (0.0, -0.001)
uniform float uDamping;  // e.g. 0.999

// TD does not predeclare the fragment output; declare it explicitly.
layout(location = 0) out vec4 fragColor;

void main() {
    vec2 uv = vUV.st;
    vec4 state = texture(sTD2DInputs[0], uv);

    // Decode: position and velocity stored as 0..1, remap to -1..1
    vec2 pos = state.rg * 2.0 - 1.0; // position in NDC
    vec2 vel = state.ba * 2.0 - 1.0; // velocity

    // Apply gravity and damping
    vel += uGravity;
    vel *= uDamping;

    // Optional: sample a force field from the SECOND input, if connected.
    // GLSL TOPs can only read inputs by connection order (sTD2DInputs[i]);
    // gate on the input count so the shader still compiles with one input.
#if TD_NUM_2D_INPUTS > 1
    vec2 sampleUV = pos * 0.5 + 0.5;
    vec4 force = texture(sTD2DInputs[1], clamp(sampleUV, 0.0, 1.0));
    vel += (force.rg * 2.0 - 1.0) * 0.002;
#endif

    // Integrate position
    pos += vel * uDt;

    // Boundary: bounce
    if (abs(pos.x) > 1.0) { vel.x *= -0.5; pos.x = sign(pos.x); }
    if (abs(pos.y) > 1.0) { vel.y *= -0.5; pos.y = sign(pos.y); }

    // Re-encode to 0..1 and emit
    fragColor = TDOutputSwizzle(vec4(pos * 0.5 + 0.5, vel * 0.5 + 0.5));
}
